# Instructions ----
#' This file follows the format generated by FIMS:::use_testthat_template().
#' Necessary tests include input and output (IO) correctness [IO
#' correctness], edge-case handling [Edge handling], and built-in errors and
#' warnings [Error handling]. See `?FIMS:::use_testthat_template` for more
#' information. Every test should have a @description tag, which can only span
#' one lines, that will be used in the bookdown report of the results from
#' {testthat}. This line can be more than 80 characters.

# setup_default_DnormDistribution ----
## Setup ----
data <- FIMS::FIMSFrame(data_big)

## IO correctness ----
test_that("`setup_default_DnormDistribution()` works with correct inputs", {
  result <- FIMS:::setup_default_DnormDistribution(value = c(0.1, 0.2, 0.3), data = data)

  #' @description Test that row count follows the length of input `value`.
  expect_s3_class(result, "tbl_df")
  expect_equal(nrow(result), 3)
  expect_true(all(result[["distribution"]] == "Dnorm"))

  clear()
})

## Edge handling ----
test_that("`setup_default_DnormDistribution()` works with edge cases", {
  result <- FIMS:::setup_default_DnormDistribution(data = data, input_type = "process")

  #' @description Test that alternative input_type is retained in output.
  expect_true(all(result[["distribution_type"]] == "process"))

  clear()
})

## Error handling ----
test_that("`setup_default_DnormDistribution()` returns correct error messages", {
  #' @description Test that invalid input_type returns expected error.
  expect_error(
    object = FIMS:::setup_default_DnormDistribution(data = data, input_type = "invalid"),
    regexp = "must be one of"
  )

  clear()
})
